// Server-side fuzzy match with ranges; client just renders
function Highlight({ text, matches }: { text: string; matches: Array<[number, number]> }) {
  if (!matches.length) return <>{text}</>;
  const parts: Array<{ text: string; highlight: boolean }> = [];
  let last = 0;
  matches.sort((a, b) => a[0] - b[0]).forEach(([start, end]) => {
    if (start > last) parts.push({ text: text.slice(last, start), highlight: false });
    parts.push({ text: text.slice(start, end), highlight: true });
    last = end;
  });
  if (last < text.length) parts.push({ text: text.slice(last), highlight: false });
  return <>{parts.map((p, i) => p.highlight ? <mark key={i}>{p.text}</mark> : <span key={i}>{p.text}</span>)}</>;
}

