// Composable headless
function usePageDrop({ onFiles, accept }: Options) {
  const [over, setOver] = useState(false);
  const counter = useRef(0);

  useEffect(() => {
    const enter = (e: DragEvent) => { e.preventDefault(); counter.current++; setOver(true); };
    const leave = () => { counter.current--; if (counter.current === 0) setOver(false); };
    const drop = (e: DragEvent) => {
      e.preventDefault();
      counter.current = 0;
      setOver(false);
      const files = Array.from(e.dataTransfer?.files ?? []);
      const valid = accept ? files.filter(f => accept.test(f.type)) : files;
      if (valid.length) onFiles(valid);
    };
    const dragover = (e: DragEvent) => e.preventDefault();

    window.addEventListener('dragenter', enter);
    window.addEventListener('dragleave', leave);
    window.addEventListener('drop', drop);
    window.addEventListener('dragover', dragover);
    return () => {
      window.removeEventListener('dragenter', enter);
      window.removeEventListener('dragleave', leave);
      window.removeEventListener('drop', drop);
      window.removeEventListener('dragover', dragover);
    };
  }, [onFiles, accept]);

  return over;
}

