export function useToggle(initial = false, options?: { onChange?: (value: boolean) => void }) {
  const [v, setV] = useState(initial);
  const onChange = options?.onChange;

  const set = useCallback((nv: boolean | ((prev: boolean) => boolean)) => {
    setV((prev) => {
      const next = typeof nv === 'function' ? nv(prev) : nv;
      onChange?.(next);
      return next;
