export function useFileQueue<T extends File>(options: Options) {
  const [items, setItems] = useState<QueuedFile<T>[]>([]);

  const add = (files: T[]) => setItems(s => [...s, ...files.map(f => ({ id: nanoid(), file: f, status: 'pending' as const, progress: 0 }))]);
  const remove = (id: string) => setItems(s => s.filter(i => i.id !== id));
  const reorder = (from: number, to: number) => setItems(s => arrayMove(s, from, to));
  const retry = (id: string) => setItems(s => s.map(i => i.id === id ? { ...i, status: 'pending', progress: 0 } : i));

  // ... upload logic, concurrency control
  return { items, add, remove, reorder, retry };
}

